            ['group' => 'free_request', 'key' => 'title', 'locale' => 'en', 'text' => 'Free reservations request form'],
            ['group' => 'free_request', 'key' => 'title', 'locale' => 'cg', 'text' => 'Forma za besplatne rezervacije'],
            // Legal intro (final short version, cg/en)
            ['group' => 'free_request', 'key' => 'legal_title', 'locale' => 'en', 'text' => 'Who can submit a request?'],
            ['group' => 'free_request', 'key' => 'legal_title', 'locale' => 'cg', 'text' => 'Ko može podnijeti zahtjev?'],
            ['group' => 'free_request', 'key' => 'legal_body', 'locale' => 'en', 'text' => "Educational institutions and humanitarian organizations may request free reservations for:\n- persons with severe disabilities,\n- pupils and students in school-related activities,\n- humanitarian organizations and their beneficiaries."],
            ['group' => 'free_request', 'key' => 'legal_body', 'locale' => 'cg', 'text' => "Obrazovne ustanove i humanitarne organizacije mogu podnijeti zahtjev za besplatnu rezervaciju za:\n- lica sa teškim smetnjama,\n- učenike i studente u okviru školskih aktivnosti,\n- humanitarne organizacije i njihove korisnike."],
            ['group' => 'free_request', 'key' => 'legal_note', 'locale' => 'en', 'text' => 'Approval requires appropriate proof (e.g. school certificate, medical confirmation, or similar document).'],
            ['group' => 'free_request', 'key' => 'legal_note', 'locale' => 'cg', 'text' => 'Za odobrenje je potrebno dostaviti odgovarajući dokaz (potvrda škole, ljekara ili drugi relevantan dokument).'],
            ['group' => 'free_request', 'key' => 'legal_reference', 'locale' => 'en', 'text' => 'In accordance with: Official Gazette of Montenegro – Municipal Regulations, No. 11/2024, Decision on Fees for the Economic Use of Cultural Assets of the Municipality of Kotor.'],
            ['group' => 'free_request', 'key' => 'legal_reference', 'locale' => 'cg', 'text' => 'U skladu sa: Službeni list Crne Gore – Opštinski propisi, broj 11/2024, Odluka o naknadi za ekonomsko iskorišćavanje kulturnih dobara Opštine Kotor.'],

            // Backwards compatible (no longer shown in UI, kept for old deployments)
            ['group' => 'free_request', 'key' => 'legal_summary', 'locale' => 'en', 'text' => 'Temporary summary (placeholder). The official text will be provided after legal verification.'],
            ['group' => 'free_request', 'key' => 'legal_summary', 'locale' => 'cg', 'text' => 'Privremeni sažetak (placeholder). Zvanični tekst će biti dodat nakon pravne verifikacije.'],
            ['group' => 'free_request', 'key' => 'intro_note', 'locale' => 'en', 'text' => 'Submitting this form does not mean a reservation is automatically created. The data is sent to administrators who will first verify authenticity and then create reservations according to your request and our capacities. Please submit the request as early as possible. All fields are required.'],
            ['group' => 'free_request', 'key' => 'intro_note', 'locale' => 'cg', 'text' => 'Popunjena forma ne znači da je rezervacija automatski napravljena. Podaci se upućuju administratorima koji će prvo da provjere autentičnost podataka, a potom da naprave rezervaciju u skladu sa Vašim željama i našim kapacitetima. Iz tog razloga Vas molimo da što ranije pošaljete zahtjev (popunite formu) kako bi izgledi da dobijete željene termine bili što veći. Sva polja su obavezna.'],
            ['group' => 'free_request', 'key' => 'fzbr_title', 'locale' => 'en', 'text' => 'Free reservations'],
            ['group' => 'free_request', 'key' => 'fzbr_title', 'locale' => 'cg', 'text' => 'Besplatne rezervacije'],
            ['group' => 'free_request', 'key' => 'fzbr_description', 'locale' => 'en', 'text' => "The economic use fee for cultural assets is not paid by liable parties when they organise passenger transport for:\n- persons with severe sensory and physical disabilities;\n- participants in school excursions, i.e. pupils and students whose stay is organised by schools and faculties under regular programmes, or educational, sports and cultural events held in Montenegro;\n- foreign nationals who are exempt from paying fees under international conventions and agreements and who arrive in an organised manner through official humanitarian organisations to provide humanitarian aid.\n\nThe form must be accompanied by documentation proving the engagement of the agency/carrier. This documentation means a document (contract, invoice, agreement, etc.) showing that the agency/carrier has been engaged by liable parties who are exempt from payment for the purpose of an organised visit to Kotor. If you do not have these documents at the time of submission, you may send what you have now and provide the rest later.\n\nA free reservation will not be approved until all required documentation has been submitted and reviewed by an administrator."],
            ['group' => 'free_request', 'key' => 'fzbr_description', 'locale' => 'cg', 'text' => "Naknadu za ekonomsko iskorišćavanje kulturnih dobara ne plaćaju obveznici naknade pod uslovom da organizuju prevoz putnika koja su:\n- lica sa teškim čulnim i tjelesnim smetnjama;\n- učesnici školskih ekskurzija, odnosno učenici i studenti čiji boravak organizuju škole i fakulteti u okviru redovnih programa, održavanja obrazovnih, sportskih i kulturnih manifestacija sa teritorije Crne Gore;\n- strani državljani koji su po međunarodnim konvencijama i sporazumima oslobođeni plaćanja taksi i koji organizovano, preko zvaničnih humanitarnih organizacija, dolaze radi pružanja humanitarne pomoći.\n\nUz formular je potrebno priložiti dokumentaciju kojom se potvrđuje angažovanje agencije/prevoznika. Dokumentacija podrazumjeva dokument (ugovor, račun, sporazum...) gde se vidi da je agencija/prevoznik angažovan od strane obveznika koji su oslobođeni plaćanja za potrebe organizovanog dolaska u Kotor. Ukoliko u trenutku podnošenja ne raspolažete tim dokumentima, možete poslati ono što imate, a preostalu dokumentaciju dostaviti naknadno.\n\nBesplatna rezervacija neće biti odobrena dok sva neophodna dokumentacija ne bude dostavljena i pregledana od strane administratora."],
            ['group' => 'free_request', 'key' => 'fzbr_instruction', 'locale' => 'en', 'text' => 'After submitting the form, the request is sent to the Bus Kotor service administrator for review and approval. Approval depends on available capacity for the requested date as well as on the completeness of the submitted documentation. Please submit your request as early as possible — we recommend at least one day before the desired reservation date.'],
            ['group' => 'free_request', 'key' => 'fzbr_instruction', 'locale' => 'cg', 'text' => 'Nakon slanja formulara, zahtjev dolazi na pregled i odobravanje administratoru Bus Kotor servisa. Odobravanje zavisi od raspoloživih kapaciteta za traženi datum, kao i od kompletiranosti dostavljene dokumentacije. Molimo Vas da zahtjev podnesete što ranije — preporučeno najmanje jedan dan prije željenog datuma rezervacije.'],
            ['group' => 'free_request', 'key' => 'documents_label', 'locale' => 'en', 'text' => 'Basis for a free reservation request'],
            ['group' => 'free_request', 'key' => 'documents_label', 'locale' => 'cg', 'text' => 'Osnov za zahtjev za besplatnu rezervaciju'],
            ['group' => 'free_request', 'key' => 'documents_hint', 'locale' => 'en', 'text' => "Attach documentation proving the engagement of the agency/carrier (contract, invoice, agreement, etc.) by liable parties exempt from payment for an organised visit to Kotor.\n\nIf you do not yet have all required documents, you may submit what you have now and provide the remainder later."],
            ['group' => 'free_request', 'key' => 'documents_hint', 'locale' => 'cg', 'text' => "Priložite dokumentaciju kojom se potvrđuje angažovanje agencije/prevoznika (ugovor, račun, sporazum...).\n\nUkoliko trenutno ne raspolažete svim potrebnim dokumentima, možete poslati ono što imate, a preostalu dokumentaciju dostaviti naknadno."],
