            return [
                ...$row,
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }, $rows);

        DB::table('ui_translations')->upsert(
            $rows,
            ['group', 'key', 'locale'],
            ['text', 'updated_at']
        );

        // Invalidate UiText cache (group maps + any-locale fallbacks) so new texts apply immediately.
